        "question": "How many sharps are in the key of E major?",
        "options": ["2", "4", "3", "5"],
        "correctAnswer": 2,
        "explanation": "E major has four sharps: F#, C#, G#, and D#."
      },
      {
        "question": "What does a treble clef indicate?",
        "options": ["High pitches", "Low pitches", "Rhythm", "Dynamics"],
        "correctAnswer": 0,
        "explanation": "The treble clef is used for higher-pitched notes."
      },
      {
        "question": "What is a whole note worth in beats?",
        "options": ["2", "4", "1", "3"],
        "correctAnswer": 1,
        "explanation": "A whole note is worth four beats in common time."
      }
